/* ================= QR CODE ================= */
function generateQRCodeClient(data, imgElement) {
  // Safety check if library is not ready yet
  if (typeof QRCode === 'undefined') {
    console.warn('QRCode library not loaded yet. Retrying...');
    imgElement.src = 'https://via.placeholder.com/200x200/cccccc/000000?text=Loading+QR...';
    
    // Retry after 500ms
    setTimeout(() => generateQRCodeClient(data, imgElement), 500);
    return;
  }

  QRCode.toDataURL(data, {
    width: 200,
    margin: 1,
    color: { dark: '#000000', light: '#FFFFFF' }
  })
  .then(url => {
    imgElement.src = url;
  })
  .catch(err => {
    console.error('QR Code generation failed:', err);
    imgElement.src = 'https://via.placeholder.com/200x200?text=QR+Error';
  });
}